using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .Build();

var researchTools = new ResearchTools();

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. Use the WebSearch tool to find information about topics, "
    + "and the TakeNote tool to record important findings. After researching, provide a concise summary "
    + "of your notes.")
{
    Tools = [.. AIFunctionFactory.Create(researchTools)],
};

Console.WriteLine("Research Agent Ready!");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User,
        $"Research the following topic thoroughly. Search the web for relevant information, "
        + $"take notes on key findings, then provide a final summary.\n\nTopic: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n--- Research Notes ---");
foreach (var note in researchTools.Notes)
{
    Console.WriteLine($"• {note}");
}

/// <summary>Tools available to the research agent.</summary>
sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    public IReadOnlyList<string> Notes => _notes;

    [Description("Search the web for information on a query. Returns relevant search result snippets.")]
    public async Task<string> WebSearch(string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            var response = await _httpClient.SendAsync(request);
            var html = await response.Content.ReadAsStringAsync();

            // Extract text snippets from result blocks
            var snippets = new List<string>();
            var resultSections = html.Split("class=\"result__snippet\"",
                StringSplitOptions.RemoveEmptyEntries);

            for (var i = 1; i < Math.Min(resultSections.Length, 6); i++)
            {
                var section = resultSections[i];
                var startIdx = section.IndexOf('>') + 1;
                var endIdx = section.IndexOf("</a>", StringComparison.Ordinal);
                if (startIdx > 0 && endIdx > startIdx)
                {
                    var snippet = section[startIdx..endIdx];
                    snippet = System.Text.RegularExpressions.Regex.Replace(snippet, "<[^>]+>", "");
                    snippet = System.Net.WebUtility.HtmlDecode(snippet).Trim();
                    if (!string.IsNullOrWhiteSpace(snippet))
                    {
                        snippets.Add(snippet);
                    }
                }
            }

            return snippets.Count > 0
                ? $"Search results for '{query}':\n" + string.Join("\n---\n", snippets)
                : $"No detailed results found for '{query}'. Try a different search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save an important finding or note during research. Use this to record key facts.")]
    public string TakeNote(string note)
    {
        _notes.Add(note);
        return $"Note saved ({_notes.Count} total notes recorded).";
    }
}

