using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .Build();

var researchTools = new ResearchTools();

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. Use the WebSearch tool to find information about topics, "
    + "and the TakeNote tool to record important findings. After researching, provide a concise summary "
    + "of your notes.")
{
    Tools = [.. AIFunctionFactory.Create(researchTools)],
};

Console.WriteLine("Research Agent Ready!");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User,
        $"Research the following topic thoroughly. Search the web for relevant information, "
        + $"take notes on key findings, then provide a final summary.\n\nTopic: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n--- Research Notes ---");
foreach (var note in researchTools.Notes)
{
    Console.WriteLine($"• {note}");
}

