     [Description("Search the web for information on a query. Returns relevant search result snippets.")]
     public async Task<string> WebSearch(string query)
     {
         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";

             using var request = new HttpRequestMessage(HttpMethod.Get, url);
             request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

             var response = await _httpClient.SendAsync(request);
             var html = await response.Content.ReadAsStringAsync();

             // Extract text snippets from result blocks
             var snippets = new List<string>();
             var resultSections = html.Split("class=\"result__snippet\"",
                 StringSplitOptions.RemoveEmptyEntries);

             for (var i = 1; i < Math.Min(resultSections.Length, 6); i++)
             {
                 var section = resultSections[i];
                 var startIdx = section.IndexOf('>') + 1;
                 var endIdx = section.IndexOf("</a>", StringComparison.Ordinal);
                 if (startIdx > 0 && endIdx > startIdx)
                 {
                     var snippet = section[startIdx..endIdx];
                     snippet = System.Text.RegularExpressions.Regex.Replace(snippet, "<[^>]+>", "");
                     snippet = System.Net.WebUtility.HtmlDecode(snippet).Trim();
                     if (!string.IsNullOrWhiteSpace(snippet))
                     {
                         snippets.Add(snippet);
                     }
                 }
             }

             return snippets.Count > 0
                 ? $"Search results for '{query}':\n" + string.Join("\n---\n", snippets)
                 : $"No detailed results found for '{query}'. Try a different search query.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }

     [Description("Save an important finding or note during research. Use this to record key facts.")]
     public string TakeNote(string note)
     {
         _notes.Add(note);
         return $"Note saved ({_notes.Count} total notes recorded).";
     }
 }
